from pathlib import Path
import json

ROOT = Path(__file__).resolve().parent
DATA_PATH = ROOT / "data" / "italiano.json"

PAYLOADS = [
    r'''{"nome":"Italiano","argomenti":{"romanticismo":{"titolo":"L'età del Romanticismo","sintesi":"Il Romanticismo nasce in Germania tra la fine del Settecento e l'inizio dell'Ottocento. Reagisce all'Illuminismo e al classicismo. In Italia ha un tono più civile e patriottico e si lega al Risorgimento.","sezioni":[{"titolo":"Concetti chiave","punti":["Il Romanticismo mette al centro sentimento, immaginazione e individuo, più della ragione universale dell'Illuminismo.","Parla molto di natura, popolo, nazione, storia, religione e infinito, cioè tensione verso qualcosa di assoluto.","Nasce in Germania con la rivista Athenaeum e con autori come gli Schlegel e Novalis; poi si diffonde in Inghilterra, Francia e Italia.","In Italia il dibattito inizia nel 1816 con un articolo di Madame de Staël sulla Biblioteca Italiana: invita a tradurre opere straniere per rinnovare la nostra letteratura.","I classicisti difendono tradizione e miti antichi; i romantici, come Berchet, Borsieri e Di Breme, vogliono una letteratura moderna, nazionale e vicina al popolo, e fondano Il Conciliatore.","Il Romanticismo italiano è meno estremo di quello del Nord Europa: preferisce la storia vera, l'impegno civile e l'educazione del popolo."]},{"titolo":"Il romanzo come nuovo genere","punti":["Nell'Ottocento il romanzo diventa il genere più amato perché piace al nuovo pubblico borghese e racconta la vita reale.","Il modello del romanzo storico è Walter Scott con Ivanhoe: unisce personaggi inventati e storia documentata.","Nella Lettera semiseria di Grisostomo al suo figliuolo Berchet dice che la poesia deve parlare al popolo, non a pochi eruditi o a lettori troppo raffinati.","In Italia il capolavoro del romanzo storico è I Promessi Sposi di Manzoni, che unisce invenzione, storia e messaggio morale.","Il romanzo dà voce agli umili e a chi prima restava fuori dalla letteratura, in pieno spirito romantico."]}],"collegamenti":["La pittura romantica di Friedrich, Delacroix e Hayez mostra gli stessi temi: sublime, nazione e sentimento.","Il Romanticismo inglese di Wordsworth e Coleridge anticipa i temi della natura e dell'immaginazione che arrivano in Italia nel dibattito del 1816.","L'idea romantica di popolo e di spirito nazionale, cioè identità collettiva, è importante per sociologia e antropologia del nazionalismo."]},"manzoni":{"titolo":"Alessandro Manzoni","sintesi":"Alessandro Manzoni è il maggiore scrittore del Romanticismo italiano. Dopo la conversione al cattolicesimo fonda la sua poetica sul vero storico e sull'utilità morale. Con I Promessi Sposi crea il romanzo moderno italiano e dà voce agli umili.","sezioni":[{"titolo":"Vita, idee e poetica","punti":["Nipote di Cesare Beccaria, parte da idee illuministe; il periodo a Parigi e la conversione del 1810 lo portano a un cattolicesimo liberale, che unisce fede e ragione.","Nella Lettera sul Romanticismo scrive che la letteratura deve essere utile, parlare del vero e interessare chi legge.","Rifiuta la mitologia e le invenzioni false: l'arte deve partire dalla verità storica e morale.","Per lui la Provvidenza, cioè il disegno di Dio, guida la storia anche quando sembra ingiusta; l'uomo la capisce solo con la fede.","In tutta la sua opera guarda la storia dal punto di vista degli oppressi: dà dignità letteraria agli umili e alle vittime.","Si occupa sempre della lingua: con l'edizione del 1840 dei Promessi Sposi, rivista sul fiorentino parlato colto, propone una lingua nazionale comune."]},{"titolo":"Opere e testi","punti":["In morte di Carlo Imbonati è un carme giovanile in cui il compagno morto della madre indica un ideale morale: sentire, riflettere e non tradire mai il vero. È un programma che Manzoni seguirà sempre.","La Pentecoste celebra la discesa dello Spirito Santo e la nascita della Chiesa come comunità aperta a tutti, potenti e umili.","Il cinque maggio, scritto alla morte di Napoleone, dice che la sua grandezza conta meno del giudizio della fede; la provvida sventura lo piega e può salvarlo.","Adelchi è una tragedia sulla fine del regno longobardo; nel coro per la morte di Ermengarda la sofferenza diventa purificazione.","Nel capitolo XVII dei Promessi Sposi Renzo fugge verso l'Adda: notte, paura e smarrimento, ma anche fiducia in Dio.","Nel capitolo XXXVIII dei Promessi Sposi il sugo della storia dice che i guai arrivano spesso senza colpa, ma la fiducia in Dio può renderli utili a vivere meglio.","Il romanzo, scritto tra 1821 e 1840, intreccia Renzo e Lucia con la storia del Seicento spagnolo: carestia, guerra e peste mettono alla prova Provvidenza e giustizia."]},{"titolo":"I Promessi Sposi: temi e struttura","punti":["È un romanzo storico ambientato in Lombardia tra 1628 e 1630, sotto gli spagnoli. Parte dal modello di Walter Scott, ma ha una forte originalità morale.","I protagonisti sono persone umili: per la prima volta due contadini sono al centro di una grande opera italiana.","I personaggi oppongono oppressori e vittime; ci sono figure religiose positive, come fra Cristoforo e il cardinale Borromeo, e figure negative o deboli, come don Abbondio e la monaca di Monza.","Il narratore sa tutto, usa ironia e giudizi morali e finge di copiare un manoscritto del Seicento ritrovato.","La peste del 1630 è il grande quadro finale: mette tutti sullo stesso piano e porta a compimento il disegno della Provvidenza.","Ci sono tre versioni: Fermo e Lucia, la ventisettana del 1827 e la quarantana del 1840, con lingua fiorentina e illustrazioni di Gonin."]}],"collegamenti":["Il romanzo storico di Walter Scott è il modello dei Promessi Sposi; con Dickens si possono confrontare due modi diversi di raccontare gli umili e la critica sociale.","L'attenzione di Manzoni alla folla, come nei tumulti di Milano e nella peste, anticipa studi sulla psicologia delle masse e sui comportamenti collettivi.","Francesco Hayez, amico di Manzoni e autore del suo famoso ritratto, porta in pittura il Romanticismo storico e patriottico vicino a Manzoni.","La Provvidenza di Manzoni si può confrontare con il pessimismo di Leopardi e con il fatalismo dei vinti di Verga: tre risposte diverse al dolore nella storia."]},"leopardi":{"titolo":"Giacomo Leopardi","sintesi":"Giacomo Leopardi è il più grande poeta italiano dell'Ottocento e un grande pensatore europeo. Nella sua poesia unisce un forte pessimismo filosofico a una straordinaria capacità di parlare di immaginazione, ricordo e infinito.","sezioni":[{"titolo":"Vita e pensiero","punti":["Nasce a Recanati in una famiglia nobile ma decaduta; studia moltissimo nella biblioteca del padre e acquista una cultura enorme, ma peggiora la salute.","Nel 1819 fallisce la fuga da Recanati e vive una crisi: passa dall'erudizione alla poesia del bello e poi alla ricerca del vero filosofico.","Nel pessimismo storico la natura è ancora vista come una madre buona: dava illusioni agli uomini, ma la ragione e il progresso le hanno distrutte.","Nel pessimismo cosmico, dal 1824 circa, la natura diventa matrigna: è indifferente, produce vita e dolore senza scopo, e rende infelici tutti gli esseri.","Nella teoria del piacere dice che l'uomo desidera un piacere infinito, ma ogni piacere reale è limitato; per questo la felicità piena non si raggiunge mai e resta solo nell'attesa, nell'immaginazione e nel ricordo.","La sua poetica del vago e dell'indefinito usa parole e suoni poco precisi, come lontano o notte, perché ciò che non è ben definito fa lavorare l'immaginazione.","Nell'ultima fase propone la social catena, cioè la solidarietà fra gli uomini uniti contro la natura nemica: è un pessimismo combattivo."]},{"titolo":"I Canti: testi principali","punti":["L'infinito mostra una siepe che blocca la vista ma spinge l'immaginazione verso spazi senza fine e silenzi immensi; il naufragare è dolce perché l'immaginazione supera il limite.","La sera del dì di festa oppone la calma della notte all'angoscia del poeta escluso dall'amore; il canto lontano di un artigiano fa sentire che tutto passa, anche la gloria antica.","Nel Passero solitario il poeta si confronta con un passero che vive da solo: entrambi sono isolati, ma il passero segue la natura mentre il poeta rimpiangerà la giovinezza perduta.","A Silvia trasforma la morte di Teresa Fattorini nel simbolo della fine di tutte le speranze della giovinezza; la natura promette e poi delude.","La quiete dopo la tempesta dice che il piacere è solo la fine del dolore: la gioia dopo la tempesta mostra che la natura concede solo brevi pause tra le sofferenze.","Il sabato del villaggio dice che il sabato, giorno dell'attesa, vale più della festa; il piacere sta nell'aspettare, non nel possedere, e il ragazzo non deve avere fretta di crescere.","I canti pisano-recanatesi sono chiamati grandi idilli: uniscono ricordo, paesaggio di Recanati e riflessione filosofica."]},{"titolo":"La ginestra e l'ultimo Leopardi","punti":["La ginestra o il fiore del deserto, scritta nel 1836 vicino al Vesuvio, è il testamento poetico e filosofico di Leopardi.","La ginestra, che cresce sul vulcano, è il simbolo dell'uomo consapevole: non è superbo e non è vile, ma resiste senza illusioni.","Leopardi critica le magnifiche sorti e progressive, cioè l'ottimismo del suo secolo, e ricorda invece la fragilità umana.","Propone la social catena: gli uomini devono unirsi contro il vero nemico, la natura, e non combattersi tra loro.","Il pessimismo diventa la base di un'etica laica e solidale: capire il dolore porta alla fraternità, non alla resa.","Lo Zibaldone di pensieri, scritto tra 1817 e 1832 e pubblicato dopo la sua morte, è il grande laboratorio del suo pensiero, con migliaia di pagine di riflessioni."]}],"collegamenti":["La teoria del piacere, cioè il desiderio infinito che non si colma mai, dialoga con la psicologia del desiderio e con l'idea del disagio prodotto dalla civiltà.","Il tema romantico dell'infinito e del sublime avvicina Leopardi ai poeti inglesi, come Wordsworth, che raccontano una natura immensa oltre i limiti della ragione.","Il sublime nei quadri di Caspar David Friedrich, con figure sole davanti a paesaggi enormi, è il corrispettivo visivo dell'Infinito di Leopardi.","Il pessimismo cosmico di Leopardi anticipa il male di vivere di Montale: entrambi negano una Provvidenza e cercano nella poesia una forma di resistenza."]},"italia-unita":{"titolo":"L'Italia unita: quadro storico-culturale","sintesi":"Dopo il 1861 l'Italia unita deve affrontare grandi problemi: arretratezza economica, analfabetismo, questione meridionale e distanza tra Stato e popolazione. La cultura guarda al Positivismo e al compito di costruire una vera identità nazionale.","sezioni":[{"titolo":"Concetti chiave","punti":["Dopo il 1861 l'unità lascia molti problemi aperti: brigantaggio nel Sud, questione romana e analfabetismo oltre il 70 per cento.","La questione meridionale mostra il divario tra Nord e Sud: tasse e scelte economiche del nuovo Stato peggiorano la vita dei contadini del Sud, tema centrale del Verismo.","La frase attribuita a Massimo d'Azeglio, Fatta l'Italia bisogna fare gli italiani, riassume il bisogno di costruire una vera identità nazionale.","Nel secondo Ottocento domina il Positivismo, filosofia di Auguste Comte: fiducia nella scienza, nel metodo sperimentale e nel progresso. Influenza Naturalismo e Verismo.","La scuola diventa uno strumento per unire il paese: la legge Coppino del 1877 rende obbligatoria la scuola elementare; nascono libri educativi come Cuore e Pinocchio.","L'emigrazione di massa verso le Americhe e l'industrializzazione del Nord cambiano profondamente la società italiana tra Ottocento e Novecento."]},{"titolo":"Cultura e letteratura","punti":["Prima Firenze e poi Roma capitale diventano centri culturali; Milano si afferma nell'editoria e nel giornalismo ed è la città della Scapigliatura.","La letteratura dopo l'Unità oscilla tra educazione nazionale, come in De Amicis e nel Carducci poeta-vate, e critica del presente, come nella Scapigliatura e nel Verismo.","Il pubblico cresce: aumentano editoria, romanzi a puntate sui giornali e libri per l'infanzia.","La scuola adotta il modello linguistico di Manzoni, ma la discussione sulla lingua continua con la posizione storicista di Graziadio Isaia Ascoli.","La delusione dopo il Risorgimento e il contrasto tra ideali eroici e realtà borghese del nuovo Stato alimentano la ribellione della Scapigliatura e il pessimismo del Verismo."]}],"collegamenti":["Il problema dell'alfabetizzazione e della scuola come luogo di socializzazione e costruzione della nazione è centrale nella sociologia dell'educazione.","I Macchiaioli, come Fattori e Lega, rinnovano la pittura italiana negli anni dell'Unità e raccontano vita quotidiana e guerre del Risorgimento.","La questione meridionale trova la sua espressione letteraria più forte nel Verismo di Verga, che racconta una Sicilia esclusa dal progresso unitario."]},"carducci":{"titolo":"Giosuè Carducci","sintesi":"Giosuè Carducci è il poeta ufficiale dell'Italia umbertina e il primo italiano a vincere il Nobel per la letteratura. Parte da un classicismo polemico contro certo Romanticismo, poi unisce poesia civile, sperimentazione metrica e toni più intimi e malinconici.","sezioni":[{"titolo":"Vita e poetica","punti":["Nato in Versilia, studia i classici greci, latini e italiani; insegna letteratura italiana all'Università di Bologna per più di quarant'anni.","Da giovane è anticlericale e repubblicano: nell'Inno a Satana Satana è il simbolo della ragione e del progresso. Più tardi si avvicina alla monarchia e diventa poeta-vate della nuova Italia.","Si definisce difensore dei classici: rifiuta il sentimentalismo romantico, anche se nelle sue poesie restano malinconia e memoria, tratti tipici del Romanticismo.","Nelle Odi barbare prova la metrica barbara: rifà in italiano i metri antichi di Orazio e dei lirici classici. È una novità importante per la poesia del Novecento.","Ricorrono spesso la storia di Roma e del Risorgimento, i paesaggi della Maremma e delle Alpi, gli affetti familiari e il tema costante della morte.","Nel 1906 riceve il premio Nobel: la sua poesia rappresenta l'idea di una letteratura nazionale, civile e molto curata nella forma."]},{"titolo":"Opere e testi","punti":["Pianto antico è una breve poesia per la morte del figlio Dante, di tre anni: il melograno torna verde, mentre il bambino resta nella terra negra. Il contrasto è tra la natura che rinasce e la morte che non torna indietro.","Nevicata mostra la neve lenta sulla città silenziosa come specchio dell'animo del poeta: gli amici morti lo chiamano e la vita sembra ferma, in attesa della fine.","Rime nuove è una raccolta che unisce poesia civile, ricordi storici e liriche intime e malinconiche.","Odi barbare si chiamano così perché ai greci e ai romani sarebbero sembrate barbare: usano metri classici letti con accento moderno e mettono in dialogo presente e antichità romana.","La poesia di Carducci fa da ponte tra il classicismo e le novità di Pascoli e D'Annunzio, che verranno dopo di lui."]}],"collegamenti":["La metrica barbara prepara molte novità del Novecento, dal verso più libero di D'Annunzio fino alla frantumazione del verso in Ungaretti.","Il gusto di Carducci per il mondo classico e la storia romana corrisponde alla pittura celebrativa dell'Italia umbertina e ai monumenti del nuovo Stato.","La figura del poeta-vate, che costruisce memoria nazionale, mostra come la letteratura possa funzionare anche come rito civile e strumento di coesione."]},"letteratura-infanzia":{"titolo":"La letteratura per l'infanzia: Collodi e De Amicis","sintesi":"Nell'Italia dopo l'Unità la letteratura per l'infanzia serve anche a educare i nuovi cittadini. Pinocchio di Collodi e Cuore di De Amicis sono i due grandi libri di questo progetto, ma uno usa fantasia e ironia, l'altro sentimento e patriottismo.","sezioni":[{"titolo":"Concetti chiave","punti":["Dopo l'Unità la scuola elementare obbligatoria crea un nuovo pubblico di bambini lettori: la letteratura per l'infanzia nasce con un chiaro compito educativo e nazionale.","Carlo Lorenzini, chiamato Collodi, giornalista fiorentino, pubblica Le avventure di Pinocchio a puntate sul Giornale per i bambini tra 1881 e 1883.","Pinocchio è un romanzo di formazione in forma di fiaba: il burattino disobbediente, tra fughe, inganni e prove, diventa un bambino vero.","Sotto la fiaba, Pinocchio mostra l'Italia povera di fine Ottocento: fame, lavoro e giustizia spesso ingiusta. La morale di studio, lavoro e obbedienza convive con un tono ironico e ribelle che lo tiene vivo.","Edmondo De Amicis pubblica Cuore nel 1886: è il diario scolastico di Enrico Bottini, alunno di terza elementare a Torino, con lettere dei genitori e racconti mensili come La piccola vedetta lombarda e Dagli Appennini alle Ande.","Cuore propone un'etica di sacrificio, patriottismo e solidarietà tra classi sociali: la scuola è il luogo in cui figli di operai e borghesi imparano a sentirsi italiani.","I due libri mostrano due idee educative opposte: la fantasia libera e popolare di Collodi contro il sentimentalismo morale e più conformista di De Amicis."]}],"collegamenti":["Pinocchio e Cuore sono esempi chiari di socializzazione attraverso la lettura: la pedagogia dell'Ottocento usa i racconti per trasmettere regole, valori e identità nazionale.","Nello stesso periodo l'Inghilterra vittoriana crea grandi classici per l'infanzia, da Alice nel Paese delle Meraviglie di Carroll ai romanzi di Dickens con bambini protagonisti come Oliver Twist.","L'attenzione al mondo dell'infanzia ritorna, in modo diverso, nel fanciullino di Pascoli: il bambino non è solo da educare, ma diventa anche modello dello sguardo poetico."]}}}''',
    r'''{"argomenti":{"romanzo-europeo":{"titolo":"Il romanzo europeo dell'Ottocento","sintesi":"Nella seconda metà dell'Ottocento il romanzo è il genere più importante in Europa: Dickens mostra le ingiustizie dell'Inghilterra industriale, i russi entrano nella coscienza e nei grandi problemi morali, Flaubert costruisce un realismo impersonale, Wilde rappresenta l'estetismo decadente di fine secolo.","sezioni":[{"titolo":"Dickens e il romanzo russo","punti":["Charles Dickens (1812-1870) racconta l'Inghilterra vittoriana industriale: in romanzi come Oliver Twist, David Copperfield e Tempi difficili denuncia lo sfruttamento dei bambini, le workhouse, cioè gli ospizi per poveri, e la durezza dell'utilitarismo.","Dickens unisce realismo sociale, umorismo, sentimentalismo e pubblicazione a puntate: il suo successo mostra la nascita del grande pubblico borghese del romanzo.","Il romanzo russo porta il genere a una grande profondità filosofica: Tolstoj, con Guerra e pace e Anna Karenina, racconta la storia e la società e cerca il senso della vita.","Dostoevskij, con Delitto e castigo e I fratelli Karamazov, esplora la parte più nascosta della psiche, la colpa, la libertà e il male: questa scoperta dell'uomo interiore prepara il romanzo del Novecento di Svevo e Pirandello."]},{"titolo":"Flaubert e il Naturalismo francese","punti":["Gustave Flaubert con Madame Bovary (1857) fonda il romanzo realista moderno: Emma, nutrita di letture romantiche, cerca nell'adulterio e nel lusso una vita come nei suoi sogni e finisce per uccidersi.","Il bovarismo indica da allora l'insoddisfazione di chi si immagina diverso da ciò che è: è la distanza, impossibile da colmare, fra i sogni romantici e la mediocrità della provincia borghese.","Flaubert sostiene l'impersonalità: l'autore deve essere presente ma invisibile; usa il discorso indiretto libero, cioè fa entrare i pensieri di Emma nel racconto senza commentarli apertamente.","Dal realismo di Flaubert nasce il Naturalismo di Zola: il romanzo diventa quasi un esperimento scientifico sulla società e sarà il modello diretto del Verismo italiano."]},{"titolo":"Wilde e il romanzo dell'estetismo","punti":["Oscar Wilde (1854-1900) è la figura simbolo dell'estetismo inglese: anche la vita deve diventare un'opera d'arte e l'arte non deve avere uno scopo morale.","Il ritratto di Dorian Gray (1890-1891) racconta un giovane che resta sempre bello, mentre il suo ritratto invecchia e si rovina registrando i suoi peccati.","Il romanzo è un manifesto del decadentismo estetizzante: culto della bellezza, edonismo e influenza del libro velenoso, cioè del libro che corrompe, ma anche racconto morale sulla rovina di chi separa bellezza e coscienza.","La figura del dandy, pensata da Baudelaire e incarnata da Wilde, diventa il modello dell'Andrea Sperelli di D'Annunzio: l'esteta che si oppone alla massa borghese con eleganza e artificio."]}],"collegamenti":["Dickens e Wilde sono autori centrali anche nella letteratura inglese: la critica sociale vittoriana e l'estetismo di fine secolo si studiano in parallelo nelle due lingue.","Madame Bovary è il modello del realismo impersonale che Verga rende ancora più estremo con l'eclissi dell'autore; Dorian Gray è il corrispondente europeo di Andrea Sperelli nel Piacere di D'Annunzio.","Il romanzo ottocentesco è una fonte importante anche per la sociologia: Dickens mostra l'infanzia operaia e la città industriale, Flaubert la condizione femminile nella provincia borghese."]},"scapigliatura":{"titolo":"La Scapigliatura","sintesi":"La Scapigliatura è un movimento di artisti ribelli attivo a Milano e Torino negli anni 1860-1870: contro il perbenismo borghese e il tardo romanticismo manzoniano, porta in Italia i temi del maledettismo europeo, del conflitto fra ideale e realtà, del macabro e del patologico, e fa da ponte verso il Decadentismo.","sezioni":[{"titolo":"Concetti chiave","punti":["Il nome viene dal romanzo di Cletto Arrighi La Scapigliatura e il 6 febbraio (1862): scapigliato traduce il francese bohémien, cioè l'artista dalla vita disordinata e anticonformista.","Gli scapigliati, come Emilio Praga, Arrigo Boito, Iginio Ugo Tarchetti e Camillo Boito, vivono il conflitto fra arte e società borghese nell'Italia dopo l'Unità, che appare deludente rispetto agli ideali del Risorgimento.","Il tema centrale è il dualismo: l'artista è diviso fra ideale e vero, fra il desiderio di purezza e l'attrazione per il brutto, il malato e il macabro; Preludio di Boito è il testo-manifesto di questa visione.","La Scapigliatura si ribella a Manzoni e al romanticismo educativo e guarda ai modelli stranieri: Baudelaire, Hoffmann, Poe, Heine.","Anche se non produce capolavori assoluti, il movimento rinnova la cultura italiana e prepara sia il Verismo, con l'attenzione al vero anche sgradevole, sia il Decadentismo, con il gusto per il morboso."]},{"titolo":"Tarchetti e Fosca","punti":["Iginio Ugo Tarchetti (1839-1869) è il narratore più importante della Scapigliatura; muore molto giovane di tifo e incarna l'immagine dell'artista maledetto.","Fosca (1869, incompiuto) racconta il triangolo fra il giovane ufficiale Giorgio, la bella e sana Clara e Fosca, donna molto brutta e malata che lo lega a sé con una passione morbosa.","Nel brano chiamato la donna scheletro, la bruttezza spettrale di Fosca è descritta con un fascino quasi da orrore: la magrezza fa vedere lo scheletro, gli occhi sono enormi, l'orrore attira.","Il romanzo capovolge i modelli romantici dell'amore: l'attrazione per la malattia e per la morte anticipa l'erotismo decadente e lo studio di una psiche ossessiva.","Fosca rappresenta l'amore come malattia e contagio: Giorgio si ammala a sua volta e mostra la forza distruttiva dell'irrazionale sulla persona."]}],"collegamenti":["Il maledettismo scapigliato nasce da Baudelaire e prepara il Decadentismo italiano: la linea Tarchetti-Fogazzaro-D'Annunzio mostra come cresce il gusto per il morboso.","La Scapigliatura è anche un movimento pittorico: Tranquillo Cremona e Daniele Ranzoni sciolgono i contorni in atmosfere sfumate e si ribellano all'accademismo come gli scrittori si ribellano al manzonismo.","Il fascino scapigliato per la malattia nervosa e l'isteria riflette il dibattito scientifico dell'Ottocento sulla psicopatologia, che arriverà agli studi di Charcot e poi alla psicoanalisi."]},"naturalismo-verismo":{"titolo":"Naturalismo francese e Verismo italiano","sintesi":"Il Naturalismo francese, teorizzato da Zola a partire dal Positivismo, applica al romanzo un metodo scientifico: l'uomo è condizionato da eredità e ambiente. Il Verismo italiano di Verga e Capuana riprende l'impersonalità ma la rende ancora più forte, senza fiducia nel progresso e con attenzione al mondo fermo delle classi popolari del Sud.","sezioni":[{"titolo":"Il Naturalismo francese","punti":["Il Naturalismo nasce in Francia negli anni 1870 sullo sfondo del Positivismo di Comte, del determinismo di Taine, cioè razza, ambiente e momento storico, e della medicina sperimentale di Claude Bernard.","Émile Zola, nel Romanzo sperimentale (1880), presenta lo scrittore come uno scienziato: il romanzo è un esperimento che osserva come i personaggi, condizionati da ereditarietà e ambiente, reagiscono alle situazioni.","Il ciclo dei Rougon-Macquart, formato da venti romanzi, segue una famiglia sotto il Secondo Impero e studia la trasmissione ereditaria dei difetti e la pressione dei diversi ambienti sociali, come in L'Assommoir e Germinal.","I precursori sono Flaubert, per l'impersonalità, e i fratelli Goncourt, che con Germinie Lacerteux sostengono il diritto del romanzo a studiare anche le classi più povere come documento umano.","Il Naturalismo ha un intento progressista: denunciare in modo scientifico i mali sociali per aiutare a correggerli."]},{"titolo":"Il Verismo italiano","punti":["Il Verismo nasce a Milano fra il 1878 e il 1881 grazie ai siciliani Giovanni Verga e Luigi Capuana, che è il teorico del movimento, sotto l'influenza del modello di Zola.","Condivide con il Naturalismo l'impersonalità e l'attenzione ai ceti umili, ma è diverso: non ha fiducia positivista nel progresso, non vuole proporre riforme e guarda il mondo con un pessimismo fatalista.","La tecnica di Verga dell'eclissi dell'autore va oltre Zola: il narratore sparisce e la voce narrante si confonde con il mondo raccontato, prendendone mentalità e linguaggio; questo processo si chiama regressione.","Mentre Zola descrive il proletariato urbano e industriale, i veristi raccontano l'Italia rurale e meridionale: la Sicilia di Verga, la Napoli di Matilde Serao, la Sardegna di Grazia Deledda.","Documento umano e forma inerente al soggetto sono i principi fondamentali: l'opera deve sembrare nata da sola, senza che il filtro dell'autore si veda."]}],"collegamenti":["Il determinismo naturalista, cioè l'idea che l'uomo sia il prodotto di eredità e ambiente, dialoga con il Positivismo di Comte e con la nascita della sociologia scientifica.","Il realismo sociale di Dickens anticipa il Naturalismo nella denuncia delle condizioni operaie, ma usa strumenti sentimentali e umoristici invece di un metodo dichiaratamente scientifico.","Il confronto fra Germinal di Zola e I Malavoglia di Verga mostra la differenza principale: nel primo c'è una speranza di riscatto collettivo, nel secondo dominano l'ideale dell'ostrica e il fatalismo."]},"verga":{"titolo":"Giovanni Verga","sintesi":"Giovanni Verga (Catania 1840-1922) è il maggiore scrittore del Verismo italiano. Dopo i primi romanzi mondani, con Nedda e poi con Vita dei campi e I Malavoglia apre una narrativa nuova: l'autore si nasconde, il narratore guarda il mondo dal basso e i vinti vengono travolti dalla fiumana del progresso, cioè dalla grande spinta del cambiamento.","sezioni":[{"titolo":"Vita, idee, poetica","punti":["Nato a Catania in una famiglia di proprietari terrieri, vive a Firenze e poi a Milano dal 1872 al 1893, dove conosce la Scapigliatura e passa al Verismo; poi torna a Catania.","La svolta verista arriva con Nedda (1874) e si compie con Rosso Malpelo (1878): Verga lascia i romanzi mondani e sceglie il mondo dei contadini e dei pescatori siciliani.","La poetica dell'impersonalità dice che l'opera deve sembrare fatta da sé: la mano dell'artista deve restare invisibile, come scrive nella lettera-prefazione a L'amante di Gramigna del 1880.","Con regressione ed eclissi il narratore entra nel mondo rappresentato e ne prende punto di vista, valori e linguaggio, con proverbi, sintassi popolare, discorso indiretto libero e straniamento.","Nel pessimismo di Verga la lotta per la vita domina tutta la società: chi prova a migliorare la propria condizione diventa un vinto travolto dalla fiumana del progresso.","L'ideale dell'ostrica dice che, come l'ostrica vive solo attaccata allo scoglio, così gli umili sono al sicuro solo se restano uniti alla famiglia e alla tradizione; chi se ne stacca si perde.","Il ciclo dei Vinti doveva comprendere cinque romanzi, dalla plebe fino alle classi alte: Verga ne scrive solo due, I Malavoglia (1881) e Mastro-don Gesualdo (1889)."]},{"titolo":"Novelle","punti":["Nedda (1874) è un bozzetto siciliano che apre la fase verista: la raccoglitrice di olive perde madre, amante e figlia in una catena di miserie, ma il narratore partecipa ancora con pietà.","Rosso Malpelo (Vita dei campi, 1880) racconta il ragazzo della cava, creduto cattivo perché ha i capelli rossi: finisce per assorbire la logica crudele del suo ambiente; è un capolavoro della regressione, perché il narratore parla con la voce e i pregiudizi della comunità.","Fantasticheria (Vita dei campi), rivolta a una dama elegante, spiega l'ideale dell'ostrica e anticipa il mondo dei Malavoglia: per capire i poveri bisogna farsi piccoli come loro.","La lupa (Vita dei campi) racconta la gnà Pina, dominata da una passione divorante per il genero Nanni, che va verso la morte: il desiderio appare come una forza tragica e arcaica.","La roba (Novelle rusticane, 1883) mostra Mazzarò, che sacrifica tutto all'accumulo della roba; davanti alla morte impazzisce e grida \"Roba mia, vientene con me\": la proprietà diventa una forma di alienazione.","Libertà (Novelle rusticane) racconta la rivolta contadina di Bronte del 1860 e la repressione: la libertà promessa dal Risorgimento resta oscura e tradita per i contadini; è la storia vista dal basso."]},{"titolo":"I Malavoglia e Mastro-don Gesualdo","punti":["I Malavoglia (1881) racconta la rovina della famiglia Toscano di Aci Trezza: il debito dei lupini, il naufragio della Provvidenza, la perdita della casa del nespolo e la lenta ripresa del giovane Alessi.","Nella prefazione Verga presenta il progetto del ciclo dei Vinti: studiare la fiumana del progresso fin dalle origini e osservare i meccanismi che travolgono i più deboli a ogni livello sociale.","L'incipit porta il lettore subito dentro il mondo del paese, con il proverbio degli uomini fatti come le dita della mano: la tecnica corale fa parlare direttamente la comunità.","Il romanzo oppone i valori antichi della famiglia e della casa, difesi da padron 'Ntoni e dai suoi proverbi, alla modernità che distrugge questi legami, rappresentata dal giovane 'Ntoni, che parte e non riesce più a tornare davvero.","Mastro-don Gesualdo (1889) sale al gradino sociale successivo: il muratore arricchito Gesualdo Motta conquista la roba e un matrimonio nobile, ma resta estraneo ai nobili e tradisce la sua classe; muore solo, nell'indifferenza dei servi.","Il titolo stesso è un ossimoro sociale: mastro, cioè l'operaio, e don, cioè il signore, non si uniscono mai; la logica del denaro divora ogni affetto, secondo il pessimismo senza riscatto di Verga."]}],"collegamenti":["La famiglia patriarcale dei Malavoglia e la sua crisi davanti alla modernizzazione sono un buon caso di studio per la sociologia della famiglia e del cambiamento sociale.","Il confronto con il realismo sociale inglese di Dickens mette in luce la particolarità di Verga: niente interventi del narratore e nessun lieto fine, ma impersonalità e pessimismo radicale.","Il Quarto Stato di Pellizza da Volpedo e la pittura verista di Fattori rappresentano lo stesso mondo contadino e proletario che Verga porta nei suoi racconti e romanzi.","Rosso Malpelo dialoga con Ciaula scopre la luna di Pirandello: c'è lo stesso scenario delle miniere di zolfo siciliane, ma al posto dell'oggettività verista arriva la scoperta interiore e umoristica del personaggio."]},"decadentismo":{"titolo":"Il Decadentismo, Baudelaire e il Simbolismo","sintesi":"Il Decadentismo è una grande corrente europea di fine Ottocento che rifiuta il Positivismo: la realtà è un mistero e solo l'arte può intuirlo. Baudelaire è il precursore, i poeti maledetti e il Simbolismo francese sviluppano questa visione, mentre l'estetismo la trasforma in stile di vita; in Italia i protagonisti sono Pascoli e D'Annunzio.","sezioni":[{"titolo":"Poetica, temi, personaggi","punti":["Il termine nasce in Francia come parola offensiva, décadent, ma gli artisti lo trasformano in un segno di orgoglio: la decadenza della civiltà borghese diventa una condizione speciale di sensibilità.","Contro la ragione positivista, il Decadentismo afferma che la realtà vera sta oltre le apparenze: nell'inconscio, nel mistero, nelle corrispondenze segrete fra le cose, che si possono cogliere solo con l'intuizione poetica.","Gli strumenti della conoscenza decadente sono modi irrazionali: sogno, malattia, follia, estasi, sinestesie, cioè mescolanze dei sensi; il poeta è un veggente, come dice Rimbaud, e l'arte è la forma più alta di conoscenza.","Il linguaggio diventa musica e suggestione: il simbolo non descrive, ma fa intuire; la poesia pura rifiuta l'uso normale e comunicativo della lingua.","Figure tipiche del decadentismo sono l'esteta, come Des Esseintes, Dorian Gray e Andrea Sperelli, il maledetto, il fanciullino di Pascoli, il superuomo di D'Annunzio e l'inetto: sono tutte immagini della crisi dell'uomo borghese.","Vivere la vita come un'opera d'arte: l'estetismo sostituisce l'etica con l'estetica, il bene con il bello; ma i romanzi decadenti mostrano quasi sempre il fallimento di questo progetto."]},{"titolo":"Baudelaire e i poeti maledetti","punti":["Charles Baudelaire (1821-1867), con I fiori del male (1857), apre la poesia moderna: lo spleen, cioè noia e disgusto esistenziale, si oppone all'ideale, e la bellezza può nascere anche dal male e dal fango della città moderna.","Nel sonetto Corrispondenze la natura è una foresta di simboli: profumi, colori e suoni si richiamano tra loro; è il manifesto del Simbolismo e della sinestesia.","L'albatro, grande uccello marino maestoso in volo ma goffo e deriso sul ponte della nave, è il simbolo del poeta: le sue ali da gigante gli impediscono di camminare e lo rendono un escluso nella società borghese.","Con la perdita dell'aureola Baudelaire registra la fine del ruolo sacro del poeta nella società di massa: è un tema che continuerà nella lirica moderna fino a Montale.","I poeti maledetti, Verlaine, Rimbaud e Mallarmé, sviluppano il Simbolismo: musicalità del verso in Verlaine, sregolatezza di tutti i sensi e poeta veggente in Rimbaud, poesia come enigma assoluto in Mallarmé."]}],"collegamenti":["L'estetismo inglese di Walter Pater e Oscar Wilde è il ramo britannico del Decadentismo: Il ritratto di Dorian Gray trasforma in romanzo il culto della bellezza e della vita come opera d'arte.","Il Simbolismo nella pittura, con Moreau, Redon e Böcklin, e poi la Secessione di Klimt, esprime lo stesso rifiuto del naturalismo: l'immagine diventa simbolo del mistero e dell'inconscio.","L'attenzione decadente per l'inconscio e per il sogno anticipa e accompagna la nascita della psicoanalisi di Freud: L'interpretazione dei sogni esce nel 1899, nel pieno di questa stagione culturale."]}}}''',
    r'''{"argomenti":{"pascoli":{"titolo":"Giovanni Pascoli","sintesi":"Giovanni Pascoli (San Mauro di Romagna 1855 - Bologna 1912) è, insieme a D'Annunzio, uno dei principali autori del Decadentismo italiano. Dopo l'uccisione del padre e molti lutti familiari, sviluppa la poetica del fanciullino e una poesia delle piccole cose, piena di simboli, inquietudine e suoni ricercati, cambiando profondamente il linguaggio poetico italiano.","sezioni":[{"titolo":"Vita, idee, poetica","punti":["Il 10 agosto 1867 il padre Ruggero, amministratore di una tenuta dei principi Torlonia, viene ucciso da sconosciuti. Questo delitto mai punito e le morti successive in famiglia segnano per sempre la vita e la poesia di Pascoli.","Cerca di ricostruire il nido familiare vivendo con le sorelle Ida e Mariù. Il nido è il simbolo centrale della sua poesia: è un rifugio sicuro dal mondo esterno, ma allo stesso tempo impedisce l'amore adulto.","Insegna latino e greco e nel 1905 prende il posto di Carducci all'Università di Bologna. È anche un importante poeta in latino.","La poetica del fanciullino, spiegata nel saggio del 1897, dice che in ogni persona vive un bambino capace di guardare il mondo con stupore. Il poeta è chi riesce a far parlare questo sguardo, e la poesia nasce da un'intuizione immediata, non dal ragionamento.","La poesia delle piccole cose trasforma oggetti semplici, elementi della campagna, uccelli e fiori in simboli pieni di mistero, paura e pensiero della morte. Li descrive con grande precisione scientifica.","Rinnova il linguaggio poetico con onomatopee, cioè parole che imitano suoni, fonosimbolismo, cioè uso dei suoni per creare significati, sinestesie, cioè mescolanza di sensazioni diverse, frasi spezzate e unione di lingua colta, dialetto e linguaggi tecnici. Contini parla di linguaggio pre-grammaticale e post-grammaticale.","Dal punto di vista politico passa da un socialismo umanitario a un nazionalismo più forte, come mostra il discorso La grande proletaria si è mossa del 1911, favorevole alla guerra di Libia."]},{"titolo":"Opere e testi","punti":["Il fanciullino (1897) è il suo saggio più importante sulla poesia: la poesia non è retorica, ma sguardo infantile e meravigliato sulle cose. Questo fanciullo vive in ogni uomo e la poesia ha anche un valore di conforto e fratellanza.","Lavandare (Myricae) presenta una scena di campagna. L'aratro lasciato nel campo e il canto delle lavandaie diventano simboli di abbandono, solitudine e di una vita rimasta incompleta.","Novembre (Myricae) mostra l'estate di San Martino, che sembra una falsa primavera. Però gli alberi sono senza foglie e il silenzio fa capire che è l'estate fredda dei morti: la natura appare come un'illusione che nasconde la morte.","X Agosto (Myricae), scritto pensando all'anniversario della morte del padre, mette in parallelo la rondine uccisa mentre torna al nido e l'uomo assassinato. Le stelle cadenti sembrano il pianto del cielo su una Terra vista come luogo del male.","L'assiuolo (Myricae) usa il verso dell'uccello notturno, il chiù, per creare un'angoscia crescente: da un vago timore si arriva a un vero pianto di morte. È un capolavoro di fonosimbolismo e di paesaggio che esprime lo stato d'animo.","Digitale purpurea (Poemetti) racconta il ricordo di un fiore proibito nel giardino del collegio, bello ma mortale. Il suo profumo diventa simbolo dell'attrazione inquieta verso l'eros e la morte.","Il gelsomino notturno (Canti di Castelvecchio, 1903), scritto per le nozze di un amico, usa il fiore che si apre di notte come simbolo dell'unione matrimoniale e della nascita di una nuova vita. Il poeta però resta fuori da questa esperienza amorosa.","Nebbia (Canti di Castelvecchio) è una preghiera alla nebbia perché nasconda ciò che è lontano. Il poeta vuole vedere solo la piccola siepe del suo orto, come rifugio dal dolore del mondo e dal richiamo dei morti."]},{"titolo":"Myricae e i Canti di Castelvecchio","punti":["Myricae (1891-1900) prende il titolo da Virgilio e dalle umili tamerici. Contiene brevi poesie sulla campagna e sulle stagioni, attraversate dal ricordo dei morti e da simboli di lutto.","I Canti di Castelvecchio (1903) continuano il discorso di Myricae con un respiro più ampio: tornano le stagioni della Garfagnana, il simbolo del nido, i morti e un fonosimbolismo ormai maturo.","La natura di Pascoli non è serena e tranquilla. Dietro ogni particolare realistico si apre sempre un mistero, un presagio di morte e un'angoscia universale.","La metrica resta tradizionale, ma viene rinnovata dall'interno con pause, puntini di sospensione, enjambement, cioè frasi che continuano nel verso dopo, e rime interne, che rompono il ritmo classico.","Pascoli è considerato un padre della poesia italiana del Novecento. Da lui derivano i crepuscolari, Ungaretti e Montale, soprattutto per l'attenzione alle cose semplici e per la fine dell'io solenne della poesia tradizionale."]}],"collegamenti":[{"materia":"scienze-umane","testo":"La poetica del fanciullino si collega alla psicologia dello sviluppo e alla riscoperta novecentesca dell'infanzia come età con modi propri di pensare e di sentire."},{"materia":"arte","testo":"Il simbolismo di Pascoli nelle piccole cose e nei fiori richiama il Simbolismo europeo in pittura e le atmosfere sospese del Divisionismo italiano, per esempio in Segantini e Previati."},{"materia":"italiano","testo":"Si può confrontare Pascoli con D'Annunzio: due forme opposte di Decadentismo, il nido contro il superuomo, le piccole cose contro il panismo vitalistico, ma con in comune la parola usata come musica e simbolo."},{"materia":"inglese","testo":"Lo sguardo infantile e visionario sulla natura avvicina il fanciullino di Pascoli alla poesia romantica inglese di Wordsworth, secondo cui il bambino è padre dell'uomo."}]},"dannunzio":{"titolo":"Gabriele D'Annunzio","sintesi":"Gabriele D'Annunzio (Pescara 1863 - Gardone 1938) rappresenta il Decadentismo italiano nella forma più estetica ed eroica. Parte dall'estetismo del Piacere, passa al superomismo ispirato a Nietzsche e arriva al panismo di Alcyone. Poeta, romanziere, autore di teatro e personaggio pubblico, trasforma la propria vita in un'opera d'arte e influenza molto la lingua, il costume e la politica italiana.","sezioni":[{"titolo":"Vita, idee, poetica","punti":["Esordisce a sedici anni con Primo vere. A Roma lavora come cronista mondano e costruisce l'immagine dell'esteta. La vita di lusso, gli amori famosi come quello con Eleonora Duse e i debiti diventano parte stessa della sua opera.","L'estetismo è il culto della bellezza e dell'arte come valori superiori a tutto, anche alla morale. Nel Piacere questo principio è riassunto nell'idea che bisogna fare della propria vita un'opera d'arte.","Il superomismo nasce dalla lettura di Nietzsche negli anni Novanta. D'Annunzio ne ricava il mito di un individuo eccezionale che rifiuta la mediocrità della società democratica e vuole diventare guida estetica e politica della nazione, come nelle Vergini delle rocce.","Il panismo è la fusione totale dell'io con la natura, vissuta come estasi e trasformazione. Il prefisso pan richiama il tutto e il dio Pan, e indica lo scioglimento sensuale della persona nel paesaggio.","Favorevole all'intervento nella Prima guerra mondiale, compie imprese spettacolari come il volo su Vienna. Tra il 1919 e il 1920 guida l'impresa di Fiume: il suo modo di fare politica come spettacolo anticipa riti e stile del fascismo.","È un grande maestro della parola: usa un lessico ricco e raffinato, recupera parole rare e preziose e con il verso libero delle Laudi rinnova profondamente la metrica italiana."]},{"titolo":"Opere e testi","punti":["Il piacere (1889) è il suo primo romanzo. Il conte Andrea Sperelli, esteta romano e ultimo erede di una razza intellettuale, vive tra arte e amori, diviso fra Elena Muti e Maria Ferres. Nel protagonista si vede anche la critica dell'autore agli effetti falsi e corrotti dell'estetismo sulla vita morale.","Canto novo (1882) è una raccolta giovanile piena di energia vitale e luminosa. In O falce di luna calante la luna che scende sul mare addormentato crea una scena notturna molto musicale e sensuale.","La sera fiesolana (Alcyone, 1899) canta la bellezza della sera sulle colline vicino a Firenze con una struttura che ricorda la lauda di san Francesco. La sera è descritta come una donna con le perle sulla fronte e ogni strofa finisce con un ritornello di lode.","La pioggia nel pineto (Alcyone, 1902) è il capolavoro del panismo. La pioggia estiva nella pineta della Versilia trasforma Ermione e il poeta in creature quasi vegetali. Onomatopee e musica delle parole realizzano la fusione completa tra uomo e natura.","Alcyone è il terzo libro delle Laudi, dopo Maia ed Elettra. È il diario lirico di un'estate in Versilia e rappresenta una pausa rispetto al superomismo, dominata invece da grazia e fusione panica con la natura.","Il teatro, con La figlia di Iorio, e il Notturno (1916-1921), scritto quasi cieco su strisce di carta, mostrano l'ultimo D'Annunzio, più frammentario e legato al ricordo."]}],"collegamenti":[{"materia":"inglese","testo":"Andrea Sperelli e Dorian Gray sono i due grandi esteti del romanzo decadente europeo: entrambi mostrano il fallimento morale del progetto di trasformare la vita in un'opera d'arte."},{"materia":"arte","testo":"Il Vittoriale degli Italiani, la casa-museo di D'Annunzio sul Garda, traduce in architettura il suo estetismo: la vita intera diventa scena artistica, con legami al gusto liberty e simbolista."},{"materia":"scienze-umane","testo":"D'Annunzio inventa una politica di massa fatta di spettacolo, discorsi, riti e simboli, soprattutto a Fiume: è un esempio utile per studiare il carisma e la comunicazione politica moderna."},{"materia":"italiano","testo":"Il superuomo di D'Annunzio e l'inetto di Svevo sono due figure opposte ma legate alla stessa crisi del soggetto: da una parte il potenziamento immaginario dell'io, dall'altra la sua analisi e dissoluzione."}]}}}''',
    r'''{"argomenti":{"avanguardie":{"titolo":"La modernità che cambia la poesia: crepuscolari, vociani e futuristi","sintesi":"Nel primo Novecento la poesia italiana cambia profondamente. I crepuscolari mettono in crisi l'idea del poeta-guida, i vociani usano spesso il frammento autobiografico, i futuristi di Marinetti vogliono distruggere la sintassi tradizionale ed esaltano la macchina. La modernità spezza così la tradizione lirica.","sezioni":[{"titolo":"I crepuscolari","punti":["Il nome crepuscolare viene dal critico Borgese nel 1910. Indica una poesia dimessa, dai toni bassi, come un tramonto spento dopo la grande poesia di Carducci, Pascoli e D'Annunzio.","I temi sono le piccole cose quotidiane e un po' kitsch, cioè di gusto mediocre: gli interni borghesi, le suore, gli organetti, i giardini tristi. Il poeta quasi si vergogna di esserlo.","Sergio Corazzini, in Desolazione del povero poeta sentimentale, dice: io non sono un poeta, sono soltanto un piccolo fanciullo che piange.","Guido Gozzano, il più importante del gruppo, riprende D'Annunzio con ironia in La signorina Felicita: usa rime insolite, prende le distanze dall'io poetico e inserisce un linguaggio colloquiale in forme tradizionali.","Il crepuscolarismo è il primo passo nella fine del ruolo pubblico del poeta: prepara la poesia antieroica e vicina alla vita quotidiana del Novecento."]},{"titolo":"Futuristi e vociani","punti":["Filippo Tommaso Marinetti pubblica il Manifesto del Futurismo su Le Figaro il 20 febbraio 1909: esalta la velocità, la macchina e la guerra definita sola igiene del mondo, e rifiuta musei e biblioteche.","Un'auto da corsa è più bella della Vittoria di Samotracia: la modernità tecnica viene esaltata contro il culto del passato.","Nel Manifesto tecnico della letteratura futurista del 1912 si propongono le parole in libertà: via sintassi, punteggiatura, aggettivi e avverbi; verbi all'infinito, analogie audaci e immaginazione senza legami logici fissi.","Il Futurismo è la prima avanguardia storica organizzata, cioè un movimento compatto con manifesti, serate-spettacolo e impegno politico interventista; influenza arte, teatro e pubblicità, per esempio con Zang Tumb Tumb di Marinetti e il paroliberismo.","I vociani, raccolti intorno alla rivista fiorentina La Voce, attiva dal 1908 al 1916 e diretta da Prezzolini, usano il frammento lirico e l'autobiografia in versi e in prosa: tra loro Rebora, Campana con i Canti Orfici e Sbarbaro.","Le riviste fiorentine, come Leonardo, La Voce e Lacerba, sono il laboratorio della cultura impegnata del primo Novecento, tra idealismo, sperimentazione e interventismo."]}],"collegamenti":[{"materia":"arte","testo":"Il Futurismo è anche un'avanguardia artistica importante: Boccioni, con opere come La città che sale e Forme uniche della continuità nello spazio, e poi Balla e Carrà, esprimono in pittura e scultura il dinamismo e la simultaneità, cioè più movimenti o momenti insieme."},{"materia":"scienze-umane","testo":"L'esaltazione futurista della velocità e della folla cittadina richiama la nuova esperienza della metropoli studiata da Simmel: la grande città cambia la vita mentale dell'individuo."},{"materia":"inglese","testo":"Le avanguardie e il modernismo inglese e americano, con Joyce, Eliot e Woolf, rompono le forme tradizionali per raccontare la frammentazione dell'esperienza moderna."}]},"romanzo-novecento":{"titolo":"La fine delle certezze: la narrativa del primo Novecento","sintesi":"Tra Ottocento e Novecento crollano molte certezze del Positivismo. La relatività di Einstein, la psicoanalisi di Freud e il pensiero di Nietzsche e Bergson mostrano un mondo senza basi stabili. Il romanzo reagisce cambiando forma: si rompono trama, tempo lineare e personaggio tradizionale. Nasce così il romanzo della crisi, di cui Svevo e Pirandello sono i maggiori autori italiani.","sezioni":[{"titolo":"Concetti chiave","punti":["La crisi del Positivismo: la stessa scienza, con la relatività e la fisica quantistica, mostra che la realtà non è oggettiva né misurabile in modo assoluto; la fiducia nel progresso si indebolisce e crolla con la Grande Guerra.","Freud e la psicoanalisi: l'io non controlla del tutto se stesso; inconscio, sogni, lapsus ed nevrosi diventano materiali del racconto e strumenti per capire il personaggio.","Nietzsche annuncia la morte di Dio e la crisi di tutti i valori; Bergson distingue il tempo della scienza dal tempo interiore della coscienza, chiamato durata, che il nuovo romanzo prova a rappresentare.","Il romanzo del Novecento lascia il narratore onnisciente e la trama ordinata: usa monologo interiore e flusso di coscienza, cioè il susseguirsi diretto dei pensieri, in Joyce e Woolf; tempo soggettivo e memoria involontaria in Proust; allegoria dell'assurdo in Kafka.","Il personaggio si disgrega: non è più un eroe che agisce, ma un inetto, un uomo senza qualità, una coscienza malata che osserva se stessa; l'identità diventa un problema, non una certezza.","In Italia la crisi del romanzo naturalista porta a La coscienza di Zeno e Il fu Mattia Pascal: narratori poco affidabili, ordine non cronologico e ironia sulla possibilità stessa di raccontare la verità."]}],"collegamenti":[{"materia":"scienze-umane","testo":"La psicoanalisi di Freud, studiata anche nelle scienze umane, offre al romanzo del Novecento una mappa dell'inconscio: Svevo la usa ma allo stesso tempo la prende anche un po' in giro nella Coscienza di Zeno."},{"materia":"inglese","testo":"Il modernismo inglese, con Joyce, Woolf ed Eliot, è il parallelo più diretto: lo stream of consciousness, cioè il flusso di coscienza, e il tempo narrativo frantumato corrispondono alle innovazioni di Svevo e Pirandello."},{"materia":"arte","testo":"Le avanguardie figurative, come cubismo, espressionismo e surrealismo, rompono il punto di vista unico proprio come il romanzo rompe il narratore onnisciente: in tutte le arti entra in crisi il modo tradizionale di rappresentare la realtà."}]}}}''',
    r'''{"argomenti":{"svevo":{"titolo":"Italo Svevo","sintesi":"Italo Svevo, nome d'arte di Ettore Schmitz (Trieste 1861-1928), è uno dei grandi autori del romanzo psicologico italiano moderno. Prima lavora come impiegato, poi come industriale, nella Trieste di cultura europea. Legge autori come Schopenhauer, Darwin e Freud. Nei suoi tre romanzi costruisce la figura dell'inetto, cioè un uomo debole e incerto. Questo tema arriva al massimo sviluppo nella Coscienza di Zeno, dove salute e malattia si scambiano di posto.","sezioni":[{"titolo":"Idee e poetica","punti":["Trieste è una città di confine dell'impero austro-ungarico, aperta al commercio e a più lingue. Per questo Svevo conosce soprattutto la cultura mitteleuropea, cioè dell'Europa centrale: Schopenhauer, Nietzsche, Darwin e poi Freud contano per lui più della tradizione letteraria italiana.","La figura più importante è l'inetto: una persona che non sa adattarsi alla lotta per la vita, pensa molto ma conclude poco. Però, col tempo, questa debolezza diventa anche una disponibilità a vedere possibilità nuove.","Svevo usa la psicoanalisi come strumento narrativo, non come cura. Conosce Freud, ma non crede davvero nella guarigione; per lui la vera analisi avviene nella scrittura.","Salute e malattia si capovolgono: i personaggi considerati sani, come Augusta o i borghesi sicuri di sé, vivono in illusioni. Zeno invece, proprio perché è inquieto e malato, capisce meglio la verità del mondo moderno.","Il narratore di Svevo non è del tutto affidabile: Zeno scrive per giustificarsi, quindi dice mezze verità, bugie e si inganna da solo. Il lettore deve capire il senso vero leggendo tra le righe.","Per molti anni Svevo non ha successo. Il riconoscimento arriva solo negli anni Venti grazie a James Joyce, che gli insegnava inglese a Trieste, e a Eugenio Montale, che gli dedica un saggio nel 1925."]},{"titolo":"Una vita e Senilità","punti":["Una vita (1892) — Alfonso Nitti è un impiegato di banca, colto ma inconcludente. Seduce la figlia del padrone, ma poi scappa davanti alle conseguenze e si suicida: è il primo vero ritratto dell'inetto.","Nel brano dell'autoritratto, la lettera di Alfonso alla madre mostra il contrasto tra i suoi sogni letterari e la grigia vita da impiegato: il sogno serve come fuga dalla realtà.","Senilità (1898) — Emilio Brentani ha trentacinque anni, ma è già spento dentro: è senile non per età, ma perché ha rinunciato a vivere. Ha una relazione con Angiolina, una ragazza del popolo che lui idealizza anche se la realtà dice il contrario.","I quattro personaggi principali sono: Emilio, l'inetto; Balli, l'amico artista pieno di energia; Amalia, la sorella che si sacrifica; Angiolina, vitale ma infedele. Emilio finisce per coinvolgere e rovinare Amalia, che muore consumata dall'etere e da un amore mai realizzato.","In Senilità Svevo rende ancora più precisa l'analisi degli autoinganni: Emilio si descrive come una persona nobile e onesta, ma in realtà agisce per egoismo. Il narratore in terza persona lo smaschera continuamente."]},{"titolo":"La coscienza di Zeno","punti":["La coscienza di Zeno (1923) non usa più un narratore in terza persona: Zeno Cosini racconta lui stesso la propria vita su invito dello psicoanalista. Il romanzo è organizzato per temi, come il fumo, la morte del padre, il matrimonio, la moglie e l'amante, gli affari, e non segue l'ordine del tempo.","La Prefazione del dottor S. apre il romanzo: lo psicoanalista, per vendicarsi del paziente che ha lasciato la cura, pubblica i suoi ricordi e avverte che dentro ci sono verità e bugie. Così il lettore capisce subito che il narratore non è del tutto attendibile.","L'ultima sigaretta: Zeno decide tante volte di smettere di fumare e scrive date solenni dappertutto, ma ogni volta ricade e prova quasi piacere nel fallimento. L'U.S., cioè ultima sigaretta, diventa il simbolo di una volontà malata, dell'autoinganno, ma anche della vita che ricomincia sempre.","Lo schiaffo in punto di morte: il padre morente colpisce Zeno con un gesto che resta ambiguo, cioè non chiaro: può essere una punizione oppure un movimento involontario. Il capitolo mostra il senso di colpa del figlio e l'impossibilità di dare un significato definitivo ai fatti.","Nel finale apocalittico, cioè catastrofico, Zeno dice di essere guarito grazie agli affari, non grazie alla psicoanalisi, ma questa guarigione è ironica. La vita stessa è una malattia e il romanzo si chiude con l'immagine profetica di un'esplosione capace di distruggere la Terra.","Il tempo del romanzo è il tempo mescolato della coscienza: il presente della scrittura e il passato ricordato si confondono. Così Svevo realizza in italiano il romanzo modernista europeo."]}],"collegamenti":["La coscienza di Zeno dialoga in modo critico con la psicoanalisi di Freud: lapsus, atti mancati e rimozione diventano elementi del racconto, ma la cura viene trattata con ironia.","James Joyce, amico e sostenitore di Svevo a Trieste, lo aiutò a farsi conoscere in Europa: Zeno e Ulysses sono due esempi altissimi del modernismo nelle rispettive letterature.","L'inetto di Svevo e il personaggio pirandelliano che si sente estraneo alla vita sono due modi simili per descrivere la crisi dell'identità nel Novecento: è un confronto classico per l'orale.","La Trieste mitteleuropea di Svevo appartiene alla stessa civiltà della Vienna di Freud e Klimt: la crisi dell'individuo attraversa la psicoanalisi, la pittura della Secessione e il romanzo."]},"pirandello":{"titolo":"Luigi Pirandello","sintesi":"Luigi Pirandello (Agrigento 1867 - Roma 1936), premio Nobel nel 1934, rinnova profondamente il romanzo e il teatro con la poetica dell'umorismo. Per lui la vita è un flusso continuo, ma le forme e le maschere sociali la bloccano. Dalla crisi di identità di Mattia Pascal alla lucida follia di Enrico IV, le sue opere mostrano che l'io non è uno solo e stabile.","sezioni":[{"titolo":"Idee e poetica","punti":["Il contrasto tra vita e forma è il centro del pensiero di Pirandello: la vita è movimento continuo, ma per vivere in società ci fissiamo in forme, cioè nome, ruoli e istituzioni, che diventano maschere e ci imprigionano.","Ogni persona porta una maschera: per gli altri siamo uno, nessuno e centomila. Chi se ne accorge può soffrire, ribellarsi oppure trovare una via di salvezza nella follia e nell'umorismo.","L'umorismo (saggio del 1908): l'arte umoristica nasce dal sentimento del contrario. La comicità è vedere qualcosa di strano e ridere, per esempio una vecchia troppo truccata; l'umorismo invece aggiunge la riflessione e scopre il dolore nascosto dietro il ridicolo.","L'umorismo scompone: rinuncia a una visione armonica e ordinata e mette in luce le contraddizioni della vita, mescolando il tragico e il comico.","C'è un relativismo della conoscenza: non esiste una verità unica e oggettiva, ma tante verità quanti sono i punti di vista, come mostra Così è, se vi pare. Per questo una comunicazione davvero autentica è impossibile.","La lanterninosofia, nel Fu Mattia Pascal, dice che ogni uomo vede il mondo con il proprio lanternino, cioè con le proprie idee e convinzioni. Nelle epoche di crisi si spengono anche i grandi lanterni, come ideologie e fedi, e resta il buio.","La sua vita è segnata dal fallimento economico della zolfara del padre e dalla malattia mentale della moglie Antonietta: esperienze dirette della maschera e della prigione familiare."]},{"titolo":"Narrativa","punti":["Il fu Mattia Pascal (1904) — creduto morto, Mattia si costruisce una nuova identità come Adriano Meis, ma capisce che senza una forma sociale, cioè documenti e stato civile, non si può vivere. Non è più né Mattia né Adriano: resta il fu Mattia Pascal, escluso da ogni identità.","Lo strappo nel cielo di carta: nel dialogo con Anselmo Paleari si parla del teatrino delle marionette. Se nel cielo di carta si aprisse uno strappo, Oreste diventerebbe Amleto: la tragedia antica viveva di certezze, mentre l'uomo moderno vede quella rottura e resta bloccato.","Uno, nessuno e centomila (1926) — Vitangelo Moscarda, partendo dall'osservazione che il suo naso pende, capisce di essere centomila persone per gli altri e nessuno per se stesso. Allora si libera di tutto e si scioglie nella vita, che muore e rinasce a ogni istante.","La carriola (Novelle per un anno) — un avvocato rispettato, prigioniero della sua forma sociale, si concede ogni giorno un piccolo gesto segreto di follia: far fare la carriola alla cagnetta. È una piccola valvola di sfogo che mostra l'assurdità del rapporto tra vita e forma.","Tu ridi (Novelle per un anno) — il signor Anselmo ride nel sonno e la moglie lo sveglia con rabbia. Quel riso, che sembra felicità, nasconde invece sogni umilianti: è un esempio concreto del sentimento del contrario.","Le Novelle per un anno, raccolta di circa 250 novelle, sono il laboratorio di Pirandello: casi umani strani e paradossali in cui la maschera si rompe e la vita irrompe."]},{"titolo":"Il teatro","punti":["Il teatro di Pirandello passa attraverso tre fasi: il teatro siciliano e verista, il teatro umoristico borghese e il teatro nel teatro, che smonta la finzione scenica, come in Sei personaggi in cerca d'autore (1921).","Enrico IV (1922) — un uomo, caduto da cavallo durante una festa in maschera, ha creduto per dodici anni di essere l'imperatore Enrico IV. Quando guarisce, sceglie però di continuare a fingersi pazzo.","Quando, dopo una provocazione, uccide il rivale Belcredi, la finzione diventa una condanna definitiva: dovrà restare folle per sempre. La maschera della pazzia è insieme rifugio dalla vita e prigione.","Enrico IV è la tragedia della forma: il protagonista, fermato in un'immagine fuori dal tempo, osserva con lucidità crudele gli altri che invecchiano dentro le loro maschere senza accorgersene.","Con Sei personaggi e con il metateatro, cioè il teatro che riflette su se stesso, Pirandello porta in scena l'impossibilità di rappresentare una verità assoluta: i personaggi non accettano gli attori che li deformano.","Riceve il premio Nobel per la letteratura nel 1934 per il modo audace e ingegnoso con cui ha rinnovato l'arte del teatro."]}],"collegamenti":["La maschera di Pirandello anticipa la sociologia dei ruoli di Goffman, cioè l'idea della vita sociale come rappresentazione: è un collegamento diretto tra letteratura e scienze umane.","Zeno e Mattia Pascal sono due narratori che raccontano la propria vita ma non riescono davvero a dominarla: insieme, Svevo e Pirandello definiscono il romanzo italiano della crisi.","Il relativismo di Pirandello e il suo metateatro dialogano con il modernismo europeo e anticipano il teatro dell'assurdo; il tema della maschera richiama anche il doppio di Dorian Gray.","La scomposizione dell'identità in Pirandello trova un parallelo visivo nel cubismo e nella pittura metafisica: la realtà appare come una costruzione fatta di punti di vista diversi."]}}}''',
    r'''{"argomenti":{"ermetismo":{"titolo":"L'Ermetismo e la poesia tra le due guerre","sintesi":"Tra le due guerre, sotto il fascismo, nasce una poesia breve, essenziale e spesso difficile, chiamata Ermetismo. Le parole non spiegano tutto: suggeriscono. Il centro è Firenze. Quasimodo e il primo Luzi sono i nomi principali. Ungaretti è il modello iniziale, mentre Montale segue una strada più personale.","sezioni":[{"titolo":"Concetti chiave","punti":["Il termine ermetico nasce da un saggio di Francesco Flora del 1936. Richiama Ermete Trismegisto, figura legata ai saperi nascosti, e indica una poesia volutamente difficile e chiusa.","I tratti principali sono: analogie senza paragoni spiegati, poca punteggiatura, pochi legami logici, parole isolate nello spazio bianco della pagina, testi brevi e molto densi.","L'idea della parola pura viene dal Simbolismo francese, soprattutto da Mallarmé e Valéry, e arriva in Italia attraverso Ungaretti. La poesia non racconta o descrive: fa nascere lampi di senso.","Il contesto è il fascismo. La chiusura dell'Ermetismo è anche una forma di difesa: rifiuta la retorica del regime con il silenzio e con la ricerca dell'assoluto.","Il centro dell'Ermetismo è Firenze, con riviste come Frontespizio e Campo di Marte. Importante anche Carlo Bo, che nel 1938 parla della letteratura come esperienza totale di vita.","Salvatore Quasimodo, Nobel nel 1959, è il poeta ermetico più famoso. Ed è subito sera riassume in tre versi la solitudine dell'uomo. Dopo la guerra passerà a una poesia più civile e impegnata, come in Alle fronde dei salici.","Ungaretti e Montale non sono ermetici in senso stretto. Ungaretti è il precursore con L'allegria; Montale costruisce una poesia personale, legata alle cose concrete e al male di vivere."]}],"collegamenti":["La poesia pura segue una linea che va da Mallarmé a Ungaretti e poi agli ermetici fiorentini. Questo aiuta a spiegare il rapporto tra simbolismo, Ungaretti ed Ermetismo.","L'essenzialità dell'Ermetismo si può avvicinare ad alcune arti tra le due guerre, dove si cercano forme pure e ridotte all'essenziale.","Il ripiegamento interiore della poesia sotto il fascismo mostra il rapporto tra intellettuali e potere totalitario: consenso, silenzio e resistenza culturale."]},"ungaretti":{"titolo":"Giuseppe Ungaretti","sintesi":"Giuseppe Ungaretti, nato ad Alessandria d'Egitto nel 1888 e morto a Milano nel 1970, cambia profondamente la poesia italiana con L'allegria. Dalla guerra in trincea nascono versi molto brevi e parole essenziali, che parlano della fragilità umana e dell'amore per la vita. Con Sentimento del tempo recupera la tradizione e apre la strada all'Ermetismo, di cui è considerato il padre.","sezioni":[{"titolo":"Poetica","punti":["Nasce ad Alessandria d'Egitto da genitori lucchesi. Si forma a Parigi, vicino alle avanguardie e ad Apollinaire. Nel 1915 parte volontario e combatte sul Carso: la trincea diventa la base della sua poesia.","Per Ungaretti conta soprattutto la parola. Tolta dal verso tradizionale e lasciata nel silenzio della pagina, la parola ritrova la sua forza originaria. In Commiato dice che ogni parola è scavata nella sua vita come un abisso.","Con L'allegria rinnova la forma poetica: quasi niente punteggiatura, versi anche di una sola parola, metro spezzato. Ogni testo ha data e luogo, come un diario di guerra.","Il titolo L'allegria, prima Allegria di naufragi, unisce due opposti. Dice la gioia improvvisa di essere vivi anche in mezzo alla morte. La guerra mostra insieme la fragilità e il valore della vita.","Con Sentimento del tempo del 1933 riprende metrica e sintassi della tradizione, da Petrarca a Leopardi e al barocco romano. È una fase più ordinata, religiosa e meditativa.","Il dolore del 1947 nasce dalla morte del figlio Antonietto e dal dramma della guerra. In questa fase la poesia torna spoglia ed è segnata dal lutto."]},{"titolo":"Testi","punti":["Veglia, scritta a Cima Quattro il 23 dicembre 1915, racconta una notte passata accanto a un compagno massacrato. La vicinanza della morte fa nascere un attaccamento fortissimo alla vita.","Fratelli, del 1916, mette al centro la parola fratelli detta tra soldati nella notte. È fragile come una foglia appena nata. La fraternità nasce dalla comune precarietà.","San Martino del Carso, del 1916, dice che del paese distrutto non resta quasi nulla. Ma nel cuore del poeta restano tutti i morti: il cuore diventa il luogo più ferito di tutti.","Soldati, scritto nel 1918, ha solo quattro versi e una sola immagine: si sta come d'autunno sugli alberi le foglie. Il soldato, e più in generale l'uomo, vive in una condizione di precarietà assoluta.","La madre, in Sentimento del tempo, immagina la madre morta davanti a Dio che aspetta il figlio per aiutarlo, come faceva in vita. È una poesia di fede e di amore che continua oltre la morte.","L'allegria nel suo insieme è insieme diario di guerra e percorso di scoperta. Dentro il naufragio del mondo, il poeta cerca un attimo di salvezza e un paese innocente."]}],"collegamenti":["I war poets inglesi, come Owen, Sassoon e Brooke, scrivono nella stessa guerra. Il confronto tra Veglia e Dulce et Decorum Est fa vedere due modi diversi di raccontare l'orrore della Prima guerra mondiale.","La rottura del verso in Ungaretti nasce anche dal contatto con le avanguardie parigine. I calligrammi di Apollinaire e il cubismo aiutano a capire il contesto visivo di L'allegria.","La trincea come trauma collettivo e la fraternità tra soldati si collegano alla psicologia del trauma e ai legami sociali nelle situazioni estreme.","Da Ungaretti nasce una parte importante dell'Ermetismo: la parola pura e l'analogia di L'allegria diventano un modello per Quasimodo e per i poeti fiorentini degli anni Trenta."]},"montale":{"titolo":"Eugenio Montale","sintesi":"Eugenio Montale, nato a Genova nel 1896 e morto a Milano nel 1981, premio Nobel nel 1975, è uno dei maggiori poeti italiani del Novecento. Da Ossi di seppia, con il male di vivere e il paesaggio ligure, fino a Satura, più ironica e quotidiana, la sua poesia attraversa tutto il secolo e lo giudica con lucidità.","sezioni":[{"titolo":"Poetica","punti":["Montale parte da un'idea netta: la poesia non può aprire mondi o dare verità complete. Può dire solo parole secche ed essenziali, e chiarire soprattutto ciò che non siamo e ciò che non vogliamo.","Il male di vivere è una condizione continua dell'esistenza. La poesia lo mostra attraverso oggetti e paesaggi concreti, senza offrire consolazioni religiose o ideologiche. Resta solo una forma di distacco, che lui chiama divina Indifferenza.","Usa spesso il correlativo oggettivo, cioè oggetti concreti che fanno capire un sentimento o un'idea senza nominarli direttamente. Per esempio il rivo strozzato, la foglia riarsa, il cavallo stramazzato.","Il varco è una possibile apertura, rara e forse solo sperata, per uscire dalla prigione dell'esistenza. Può apparire come un anello che non tiene o come una maglia rotta nella rete.","Le donne nella sua poesia hanno spesso un valore di salvezza. Clizia, cioè Irma Brandeis, è una figura alta e quasi angelica contro la barbarie. Mosca, cioè la moglie Drusilla Tanzi, è invece la presenza della memoria quotidiana.","Con Satura del 1971 cambia tono: la poesia diventa più bassa, ironica, breve, quasi da diario, e critica la società di massa. In questo modo Montale mette in discussione anche il suo passato poetico.","Montale è antifascista. Firma il manifesto di Croce e perde il posto al Gabinetto Vieusseux perché non prende la tessera fascista. Nel 1975 riceve il Nobel per una poesia originale che legge i valori umani senza illusioni."]},{"titolo":"Testi","punti":["I limoni, in Ossi di seppia del 1925, è un manifesto contro D'Annunzio. Invece delle parole nobili e rare, Montale sceglie cose semplici come i fossi e gli alberi di limoni. In questa semplicità aspetta un punto in cui il mondo possa rivelare una verità.","Meriggiare pallido e assorto descrive un pomeriggio caldo vicino a un muro d'orto, con suoni e movimenti minimi. Alla fine quell'immagine diventa simbolo della vita: camminare lungo una muraglia con in cima cocci aguzzi di bottiglia.","Spesso il male di vivere ho incontrato mostra il dolore dell'esistenza con tre immagini concrete: il rivo strozzato che gorgoglia, la foglia riarsa e il cavallo stramazzato. L'unico bene possibile è la divina Indifferenza.","Ho sceso, dandoti il braccio, almeno un milione di scale, in Satura, è dedicata alla moglie Mosca dopo la sua morte. La vita insieme continua nel vuoto lasciato da lei. È una poesia intima, semplice e molto commovente.","Ossi di seppia, del 1925, ha un titolo che richiama i resti secchi lasciati dal mare sulla riva. Questi resti diventano il simbolo di un'esistenza povera, essenziale e consumata. Anche il paesaggio ligure partecipa a questo significato.","Dopo Ossi di seppia arrivano Le occasioni del 1939, La bufera e altro del 1956, legata anche alla guerra e a Clizia, poi la svolta di Satura del 1971 e i diari finali."]}],"collegamenti":["Il correlativo oggettivo viene da T.S. Eliot, che Montale legge e traduce. Il confronto con The Waste Land mostra una comune poesia moderna fatta di aridità e frammenti.","Montale dialoga con Leopardi: il male di vivere ricorda il pessimismo cosmico, ma senza la fiducia nella solidarietà della Ginestra. Inoltre nei Limoni rovescia il modello di D'Annunzio.","La critica di Satura alla società di massa e ai nuovi linguaggi dei media si lega alle riflessioni sociologiche del Novecento sull'industria culturale.","Il paesaggio duro e antiretorico di Ossi di seppia ha punti di contatto con la pittura metafisica e con il ritorno all'ordine degli anni Venti: oggetti chiari ma pieni di enigma."]},"paradiso-struttura":{"titolo":"Il Paradiso: caratteri del poema e struttura della cantica","sintesi":"Il Paradiso è la terza cantica della Commedia. Dante, guidato prima da Beatrice e poi da san Bernardo, sale attraverso i nove cieli fino all'Empireo e alla visione di Dio. È la cantica della luce, della felicità piena e di ciò che è difficile da dire con parole umane.","sezioni":[{"titolo":"Caratteri del poema","punti":["La Commedia, scritta circa tra il 1306 e il 1321, racconta il viaggio di Dante nei tre regni dell'aldilà. Perso nella selva del peccato, il poeta compie un cammino di purificazione che vale come esempio per ogni uomo che cerca Dio.","Il titolo Commedia indica uno stile medio e soprattutto un finale positivo: si parte dal male e si arriva alla salvezza. La parola divina fu aggiunta più tardi dalla tradizione, a partire da Boccaccio e poi dall'edizione del 1555.","Tutta l'opera è costruita sui numeri: tre cantiche, cento canti, cioè 34 più 33 più 33, e terzine incatenate di endecasillabi, cioè versi di undici sillabe. Il numero tre richiama la Trinità.","Il poema si può leggere secondo quattro sensi: letterale, allegorico, morale e anagogico, cioè spirituale. Dante lo spiega nell'Epistola a Cangrande, dove dice che l'opera vuole portare gli uomini dalla miseria alla felicità.","Dante è sia il personaggio che vive il viaggio sia il poeta che lo racconta dopo. Questa doppia posizione dà forza drammatica e morale al poema.","La lingua di Dante cambia molto: dal tono duro dell'Inferno passa alla lingua alta e anche tecnica del Paradiso. Qui inventa parole nuove, come trasumanar, indiarsi e inluiarsi, per dire ciò che normalmente non si può esprimere."]},{"titolo":"Struttura della terza cantica","punti":["Il Paradiso segue la cosmologia tolemaica e aristotelica: nove cieli concentrici girano attorno alla Terra, dalla Luna fino al Primo Mobile. Oltre questi cieli c'è l'Empireo, sede immobile di Dio e dei beati.","Le anime appaiono a Dante nei vari cieli secondo il tipo della loro beatitudine: spiriti mancati ai voti, attivi, amanti, sapienti, combattenti, giusti, contemplativi. In realtà tutti stanno nell'Empireo, nella candida rosa.","Tutti i beati vedono Dio in misura diversa, ma senza gelosia. La loro pace nasce dal pieno accordo con la volontà divina: e 'n la sua volontade è nostra pace.","Le guide sono due. Beatrice, simbolo della teologia e della grazia, accompagna Dante fino al cielo delle Stelle fisse. San Bernardo, maestro di contemplazione mistica, lo guida poi nell'Empireo fino alla visione finale.","In tutta la cantica ritorna il tema dell'ineffabilità, cioè dell'impossibilità di dire tutto con le parole. La memoria e la lingua non bastano; per questo Dante usa immagini di luce, musica e similitudini.","Il Paradiso è anche una cantica politica e profetica. Dall'alto Dante giudica la corruzione della Chiesa e dell'Italia e riceve da Cacciaguida il compito di raccontare al mondo ciò che ha visto."]}],"collegamenti":["Le illustrazioni della Commedia, dalle miniature medievali a Botticelli fino a Gustave Doré, mostrano quanto sia difficile rappresentare con immagini la luce del Paradiso.","La cosmologia ordinata del Paradiso riflette la visione gerarchica della società medievale. È utile confrontarla con la visione moderna dell'universo e dell'ordine sociale.","L'ineffabile di Dante si può confrontare con la sfiducia novecentesca nella parola: Dante forza il linguaggio per parlare di Dio, mentre Montale dice che la parola può esprimere solo ciò che non siamo."]},"paradiso-canti":{"titolo":"Paradiso: canti I, III, VI, XI, XV, XXXIII","sintesi":"I sei canti proposti segnano le tappe principali della cantica: il proemio e il trasumanar nel canto I, Piccarda nel III, Giustiniano nel VI, san Francesco nell'XI, Cacciaguida nel XV e la visione finale di Dio nel XXXIII. In questi testi si vedono insieme teologia, politica, autobiografia e il continuo sforzo di dire l'indicibile.","sezioni":[{"titolo":"Canti I, III, VI","punti":["Nel canto I c'è il proemio della cantica: la gloria di Dio riempie l'universo. Dante invoca Apollo, e non solo le Muse, perché l'impresa poetica è oltre l'umano.","Sempre nel canto I compare il trasumanar, cioè il passaggio oltre l'umano. Guardando Beatrice che fissa il sole, Dante si trasforma come Glauco. Qui appare subito il tema dell'ineffabilità: questa esperienza non si può dire bene a parole. Beatrice spiega anche l'ordine dell'universo, dove ogni creatura tende al suo posto naturale.","Nel canto III, nel cielo della Luna, appaiono come immagini leggere riflesse le anime di chi non mantenne pienamente i voti. Piccarda Donati, portata via con la forza dal convento, spiega la gioia perfetta dei beati.","Nel canto III il centro è l'idea che la pace sta nel volere ciò che Dio vuole: e 'n la sua volontade è nostra pace. Ogni grado di gloria è pieno, perché in Paradiso la carità esclude l'invidia. Accanto a Piccarda c'è anche Costanza d'Altavilla.","Il canto VI è l'unico della Commedia parlato interamente da un solo personaggio: l'imperatore Giustiniano. Nel cielo di Mercurio racconta la storia dell'aquila romana da Enea fino a Carlo Magno.","Nel canto VI la storia di Roma è vista come parte del piano di Dio. L'impero prepara la redenzione. Giustiniano critica sia i ghibellini, che si prendono l'aquila, sia i guelfi, che le oppongono i gigli di Francia. Alla fine compare Romeo di Villanova, uomo giusto cacciato con ingratitudine, figura vicina a Dante esule."]},{"titolo":"Canti XI, XV, XXXIII","punti":["Nel canto XI, nel cielo del Sole e tra gli spiriti sapienti, san Tommaso d'Aquino racconta la vita di san Francesco. In Paradiso ogni ordine religioso loda il fondatore dell'altro.","Nel canto XI Francesco è presentato attraverso le sue nozze mistiche con madonna Povertà, rimasta vedova di Cristo per più di mille anni. Assisi è descritta come un Oriente da cui nasce un sole. Il canto finisce con il rimprovero di Tommaso ai domenicani ormai decaduti.","Nel canto XV, nel cielo di Marte, dalla croce luminosa esce l'anima di Cacciaguida, trisavolo di Dante. Lo accoglie con affetto, come Anchise accoglie Enea.","Nel canto XV Cacciaguida ricorda la Firenze antica, chiusa nella vecchia cerchia, semplice e onesta: donne al fuso, famiglie sobrie, pochi lussi. Questo elogio del passato diventa una condanna della Firenze presente, corrotta dal denaro e dai nuovi arrivati. Cacciaguida morì in crociata seguendo l'imperatore Corrado III.","Nel canto XXXIII san Bernardo prega la Vergine con parole altissime: Vergine madre, figlia del tuo figlio, umile e alta più che creatura. Maria ottiene per Dante la grazia della visione finale.","Sempre nel canto XXXIII Dante vede nella luce divina l'unità di tutto ciò che nell'universo appare sparso, poi i tre cerchi della Trinità e il mistero dell'Incarnazione, cioè l'immagine umana nel secondo cerchio. Alla fine l'immaginazione non basta più, ma desiderio e volontà si muovono ormai con l'amor che move il sole e l'altre stelle."]},{"titolo":"Temi trasversali dei sei canti","punti":["L'ineffabilità cresce da un canto all'altro: dal trasumanar iniziale fino al momento finale in cui l'alta fantasia cede. Il Paradiso mostra continuamente il limite del linguaggio umano.","Anche in cielo restano centrali la politica e la storia: l'impero provvidenziale raccontato da Giustiniano, la Firenze corrotta vista da Cacciaguida, la crisi degli ordini religiosi nel canto su san Francesco.","C'è poi l'autobiografia profetica. Attraverso Cacciaguida, soprattutto nei canti XV-XVII, Dante riceve la profezia dell'esilio e il compito di scrivere tutta la sua visione.","Le figure femminili accompagnano tutta la cantica: Piccarda apre con la dolcezza della volontà che coincide con quella di Dio, Maria chiude come mediatrice della visione, Beatrice resta la guida costante della verità e della grazia.","La luce è la materia stessa del Paradiso: i beati sono luci, i cieli sono splendori, e la poesia cresce per intensità luminosa fino al punto supremo di Dio."]}],"collegamenti":["Giotto, contemporaneo di Dante, dipinge ad Assisi le storie di san Francesco. Il confronto con il canto XI aiuta a vedere come il Trecento costruisce il mito francescano in pittura e in poesia.","La Firenze sobria ricordata da Cacciaguida e quella corrotta dal denaro portano al tema del cambiamento sociale e della nostalgia per una comunità più compatta contro la società mercantile.","Il canto VI del Paradiso si collega ai canti VI delle altre due cantiche, con Ciacco e Firenze nell'Inferno e con Sordello e l'Italia nel Purgatorio. Insieme formano la trilogia politica della Commedia: città, Italia, impero.","T.S. Eliot, grande lettore di Dante, considera il Paradiso un vertice della poesia europea. Nella sua poesia moderna riprende diverse immagini dantesche, creando un ponte tra le due letterature."]}}}''',
]


def load_rewrites() -> dict:
    combined = {"argomenti": {}}
    for payload in PAYLOADS:
        chunk = json.loads(payload)
        if "nome" in chunk:
            combined["nome"] = chunk["nome"]
        combined["argomenti"].update(chunk["argomenti"])
    return combined


def collegamento_testo(item):
    if isinstance(item, dict):
        return item["testo"]
    return item


def main() -> None:
    data = json.loads(DATA_PATH.read_text(encoding="utf-8"))
    rewrites = load_rewrites()

    if "nome" in rewrites:
        data["nome"] = rewrites["nome"]

    argomenti_by_id = {argomento["id"]: argomento for argomento in data["argomenti"]}
    expected = set(argomenti_by_id)
    actual = set(rewrites["argomenti"])
    if expected != actual:
        missing = sorted(expected - actual)
        extra = sorted(actual - expected)
        raise ValueError(f"Topic mismatch. Missing: {missing}. Extra: {extra}.")

    for topic_id, patch in rewrites["argomenti"].items():
        argomento = argomenti_by_id[topic_id]
        argomento["titolo"] = patch["titolo"]
        argomento["scheda"]["sintesi"] = patch["sintesi"]

        sezioni = argomento["scheda"]["sezioni"]
        if len(sezioni) != len(patch["sezioni"]):
            raise ValueError(f"Section count mismatch for {topic_id}.")
        for sezione, sezione_patch in zip(sezioni, patch["sezioni"]):
            if len(sezione["punti"]) != len(sezione_patch["punti"]):
                raise ValueError(f"Point count mismatch for {topic_id} / {sezione['titolo']}.")
            sezione["titolo"] = sezione_patch["titolo"]
            sezione["punti"] = sezione_patch["punti"]

        collegamenti = argomento["scheda"]["collegamenti"]
        if len(collegamenti) != len(patch["collegamenti"]):
            raise ValueError(f"Link count mismatch for {topic_id}.")
        for collegamento, collegamento_patch in zip(collegamenti, patch["collegamenti"]):
            collegamento["testo"] = collegamento_testo(collegamento_patch)

    DATA_PATH.write_text(json.dumps(data, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    json.loads(DATA_PATH.read_text(encoding="utf-8"))
    print(f"Updated {DATA_PATH} with simplified text for {len(expected)} topics.")


if __name__ == "__main__":
    main()
